const https = require("https");
const http = require("http");
const fs = require("fs");
const path = require("path");
const url = require("url");

const PORT = process.env.PORT || 3000;
const OPENAI_KEY = process.env.OPENAI_API_KEY || "";

// Pre-processed template image (RGBA PNG, ready for edit API)
const TEMPLATE_B64 = "";

function buildPrompt(data) {
  const name    = data.name    || "EVENT";
  const venue   = data.venue   || "";
  const day     = data.day     || "SAMSTAG";
  const date    = data.date    || "";
  const time    = data.time    || "";
  const entry   = data.entry   || "";
  const dj      = data.dj      || "";
  const genre   = data.genre   || "";
  const contact = data.contact || "";
  const extras  = data.extras  || "";

  const details = [
    time    ? `Einlass: ${time} Uhr` : "",
    entry   ? `Eintritt: ${entry}` : "",
    extras,
    contact
  ].filter(Boolean).join(" | ");

  return `Edit this nightclub event flyer. You MUST keep ALL visual elements completely identical — the woman, her pose, clothing, face, the tropical leaves, dark background, colors, lighting, bokeh effects, crowd silhouettes. Do not change anything visual.

Only change these text elements:
- Top left title → "${name.toUpperCase()}"
- Top left subtitle genre → "${genre.toUpperCase() || name.toUpperCase()}"
- Top right day label → "${day.toUpperCase()}"
- Top right date in white-bordered box → "${date}"
- Large center 3D metallic hero text → "${name}" (keep exact same 3D metallic bronze/gold script style)
- Bottom right venue name → "${venue}"
- Bottom right DJ info → "${dj ? "DJ: " + dj : ""}"
- Bottom detail line → "${details}"

Keep the exact same typography positions, styles and layout. Only update the text content.`;
}

const server = http.createServer((req, res) => {
  const parsedUrl = url.parse(req.url);

  res.setHeader("Access-Control-Allow-Origin", "*");
  res.setHeader("Access-Control-Allow-Headers", "Content-Type");
  res.setHeader("Access-Control-Allow-Methods", "POST, GET, OPTIONS");

  if (req.method === "OPTIONS") { res.writeHead(200); res.end(); return; }

  if (req.method === "GET" && parsedUrl.pathname === "/") {
    const filePath = path.join(__dirname, "public", "index.html");
    fs.readFile(filePath, (err, data) => {
      if (err) { res.writeHead(404); res.end("Not found"); return; }
      res.setHeader("Content-Type", "text/html");
      res.writeHead(200); res.end(data);
    });
    return;
  }

  if (req.method === "POST" && parsedUrl.pathname === "/api/generate") {
    if (!OPENAI_KEY) {
      res.setHeader("Content-Type", "application/json");
      res.writeHead(500);
      res.end(JSON.stringify({ error: "OPENAI_API_KEY not configured on server" }));
      return;
    }

    let body = "";
    req.on("data", chunk => body += chunk);
    req.on("end", () => {
      let parsed;
      try { parsed = JSON.parse(body); } catch(e) {
        res.writeHead(400); res.end(JSON.stringify({ error: "Invalid JSON" })); return;
      }

      const prompt = buildPrompt(parsed);

      // Convert base64 to buffer
      const imgBuffer = Buffer.from(TEMPLATE_B64, "base64");

      // Build multipart form data
      const boundary = "----FormBoundary" + Date.now().toString(36);
      const CRLF = "\r\n";

      const parts = [];

      // model
      parts.push(
        `--${boundary}${CRLF}Content-Disposition: form-data; name="model"${CRLF}${CRLF}gpt-image-1`
      );
      // prompt
      parts.push(
        `--${boundary}${CRLF}Content-Disposition: form-data; name="prompt"${CRLF}${CRLF}${prompt}`
      );
      // n
      parts.push(
        `--${boundary}${CRLF}Content-Disposition: form-data; name="n"${CRLF}${CRLF}1`
      );
      // size
      parts.push(
        `--${boundary}${CRLF}Content-Disposition: form-data; name="size"${CRLF}${CRLF}1536x1024`
      );
      // quality
      parts.push(
        `--${boundary}${CRLF}Content-Disposition: form-data; name="quality"${CRLF}${CRLF}high`
      );

      const headerStr = parts.join(CRLF) + CRLF;
      const imageHeader = `--${boundary}${CRLF}Content-Disposition: form-data; name="image[]"; filename="template.png"${CRLF}Content-Type: image/png${CRLF}${CRLF}`;
      const footer = `${CRLF}--${boundary}--${CRLF}`;

      const headerBuf = Buffer.from(headerStr, "utf8");
      const imageHeaderBuf = Buffer.from(imageHeader, "utf8");
      const footerBuf = Buffer.from(footer, "utf8");

      const totalBody = Buffer.concat([headerBuf, imageHeaderBuf, imgBuffer, footerBuf]);

      console.log(`Calling OpenAI edit API... prompt length: ${prompt.length}, image: ${imgBuffer.length} bytes`);

      const apiReq = https.request({
        hostname: "api.openai.com",
        path: "/v1/images/edits",
        method: "POST",
        headers: {
          "Authorization": "Bearer " + OPENAI_KEY,
          "Content-Type": `multipart/form-data; boundary=${boundary}`,
          "Content-Length": totalBody.length
        }
      }, (apiRes) => {
        let data = "";
        apiRes.on("data", chunk => data += chunk);
        apiRes.on("end", () => {
          console.log("OpenAI status:", apiRes.statusCode, data.substring(0, 200));
          res.setHeader("Content-Type", "application/json");
          res.writeHead(apiRes.statusCode);
          res.end(data);
        });
      });

      apiReq.on("error", (e) => {
        console.error("Error:", e.message);
        res.writeHead(500);
        res.end(JSON.stringify({ error: e.message }));
      });

      apiReq.write(totalBody);
      apiReq.end();
    });
    return;
  }

  res.writeHead(404); res.end("Not found");
});

server.timeout = 180000;
server.listen(PORT, () => console.log("NightKit running on port " + PORT));
